import type {ErrorObject, Vocabulary} from "../../types"
import limitNumber, {LimitNumberError} from "./limitNumber.js"
import multipleOf, {MultipleOfError} from "./multipleOf.js"
import limitLength from "./limitLength.js"
import pattern, {PatternError} from "./pattern.js"
import limitProperties from "./limitProperties.js"
import required, {RequiredError} from "./required.js"
import limitItems from "./limitItems.js"
import uniqueItems, {UniqueItemsError} from "./uniqueItems.js"
import constKeyword, {ConstError} from "./const.js"
import enumKeyword, {EnumError} from "./enum.js"

const validation: Vocabulary = [
  // number
  limitNumber,
  multipleOf,
  // string
  limitLength,
  pattern,
  // object
  limitProperties,
  required,
  // array
  limitItems,
  uniqueItems,
  // any
  {keyword: "type", schemaType: ["string", "array"]},
  {keyword: "nullable", schemaType: "boolean"},
  constKeyword,
  enumKeyword,
]

export default validation

type LimitError = ErrorObject<
  "maxItems" | "minItems" | "minProperties" | "maxProperties" | "minLength" | "maxLength",
  {limit: number},
  number | {$data: string}
>

export type ValidationKeywordError =
  | LimitError
  | LimitNumberError
  | MultipleOfError
  | PatternError
  | RequiredError
  | UniqueItemsError
  | ConstError
  | EnumError
